4309   assert(!Error && "invalid first arg index");
4310   --FirstArgIdx;
4311   StringRef FnName = Args[3];
4312   StringRef ImplName = Args[4];
4313   ArrayRef<StringRef> AllAspects = ArrayRef<StringRef>(Args).drop_front(5);
4314 
4315   if (AllAspects.empty())
4316     return nullptr;
4317 
4318   SmallVector<StringRef> NeededAspects;
4319   for (StringRef Aspect : AllAspects) {
4320     if (Aspect == "float") {
4321       if (llvm::any_of(
4322               llvm::make_range(std::next(CI->arg_begin(), FirstArgIdx),
4323                                CI->arg_end()),
4324               [](Value *V) { return V->getType()->isFloatingPointTy(); }))
