4339       FnName, Callee->getFunctionType(),
4340       Callee->getAttributes().removeFnAttribute(Ctx, "modular-format"));
4341   CallInst *New = cast<CallInst>(CI->clone());
4342   New->setCalledFunction(ModularFn);
4343   New->removeFnAttr("modular-format");
4344   B.Insert(New);
4345 
4346   const auto ReferenceAspect = [&](StringRef Aspect) {
4347     SmallString<20> Name = ImplName;
4348     Name += '_';
4349     Name += Aspect;
4350     Function *RelocNoneFn =
4351         Intrinsic::getOrInsertDeclaration(M, Intrinsic::reloc_none);
